// src/components/kid/PostCard.jsx
import React, { useState } from 'react';
import { postsAPI } from '../../services/api';
import toast from 'react-hot-toast';
import './PostCard.css';

const EMOJIS = ['🤩','❤️','👏','😂','😮','🔥','⭐','🌈'];

export default function PostCard({ post, onDelete, currentUserId }) {
  const [reactions, setReactions] = useState(post.reactions || []);
  const [showPicker, setShowPicker] = useState(false);
  const [loading, setLoading] = useState(false);

  const totalReactions = reactions.reduce((s, r) => s + (r.count || 0), 0);

  const handleReact = async (emoji) => {
    setShowPicker(false);
    setLoading(true);
    try {
      await postsAPI.react(post.id, emoji);
      // Optimistic update
      setReactions(prev => {
        const existing = prev.find(r => r.emoji === emoji);
        if (existing) {
          const updated = prev.map(r =>
            r.emoji === emoji ? { ...r, count: r.reacted_by_me ? r.count - 1 : r.count + 1, reacted_by_me: !r.reacted_by_me } : r
          ).filter(r => r.count > 0);
          return updated;
        }
        return [...prev, { emoji, count: 1, reacted_by_me: 1 }];
      });
    } catch (e) {
      toast.error('Could not react');
    } finally {
      setLoading(false);
    }
  };

  const timeAgo = (dateStr) => {
    const diff = Date.now() - new Date(dateStr).getTime();
    const m = Math.floor(diff / 60000);
    if (m < 1)  return 'just now';
    if (m < 60) return `${m}m ago`;
    const h = Math.floor(m / 60);
    if (h < 24) return `${h}h ago`;
    return `${Math.floor(h / 24)}d ago`;
  };

  return (
    <div className="post-card">
      <div className="post-head">
        <div className="avatar avatar-md" style={{ background: post.avatar_color || '#FFE5E5' }}>
          {post.avatar_emoji || '🦊'}
        </div>
        <div className="post-meta">
          <span className="post-name">{post.display_name || post.username}</span>
          <span className="post-time">{timeAgo(post.created_at)}</span>
        </div>
        <span className="badge badge-green post-safe">
          <span className="safe-dot" />Safe
        </span>
      </div>

      {post.content && <p className="post-content">{post.content}</p>}

      {post.image_url && (
        <div className="post-img-wrap">
          <img
            src={`${process.env.REACT_APP_API_URL?.replace('/api','') || 'http://localhost:5000'}${post.image_url}`}
            alt="post"
            className="post-img"
          />
        </div>
      )}

      <div className="post-footer">
        <div className="post-reactions">
          {reactions.map(r => (
            <button
              key={r.emoji}
              className={`react-btn ${r.reacted_by_me ? 'reacted' : ''}`}
              onClick={() => handleReact(r.emoji)}
              disabled={loading}
            >
              {r.emoji} {r.count}
            </button>
          ))}

          <div className="emoji-wrap">
            <button className="react-add" onClick={() => setShowPicker(p => !p)}>
              {totalReactions === 0 ? '😊 React' : '＋'}
            </button>
            {showPicker && (
              <div className="emoji-picker">
                {EMOJIS.map(e => (
                  <button key={e} className="emoji-pick-btn" onClick={() => handleReact(e)}>{e}</button>
                ))}
              </div>
            )}
          </div>
        </div>

        {currentUserId === post.author_id && (
          <button className="post-delete" onClick={() => onDelete && onDelete(post.id)} title="Delete post">
            🗑️
          </button>
        )}
      </div>
    </div>
  );
}
